/* RCV Analytics - Chart.js helpers  (Chart.js 3.7.x) */

var RCV_COLORS = [
    '#2563eb','#16a34a','#ea580c','#9333ea','#0891b2',
    '#d97706','#dc2626','#059669','#7c3aed','#db2777',
    '#0284c7','#65a30d','#c2410c','#7e22ce','#0e7490',
    '#b45309','#b91c1c','#047857','#6d28d9','#be185d',
];

function rcvGetColors(count) {
    var colors = [];
    for (var i = 0; i < count; i++) {
        colors.push(RCV_COLORS[i % RCV_COLORS.length]);
    }
    return colors;
}

function rcvNoData(canvasId) {
    var box = document.getElementById(canvasId);
    if (!box) return;
    box.style.display = 'none';
    var msg = document.createElement('div');
    msg.style.cssText = 'color:#94a3b8;font-size:.85em;text-align:center;padding:32px 0;';
    msg.textContent = 'Sin datos disponibles';
    box.parentNode.appendChild(msg);
}

/**
 * Dibuja valores numéricos sobre cada barra.
 * Usado como inline plugin afterDraw — se ejecuta en cada render, incluido
 * resize, por lo que las etiquetas siempre son visibles.
 */
function rcvDrawBarLabels(chart) {
    var ctx     = chart.ctx;
    var areaTop = chart.chartArea ? chart.chartArea.top : 0;

    chart.data.datasets.forEach(function(dataset, i) {
        var meta = chart.getDatasetMeta(i);
        if (meta.hidden) return;
        meta.data.forEach(function(bar, index) {
            var value = dataset.data[index];
            if (!value) return;

            /* En Chart.js 3.x bar.x y bar.y son propiedades directas */
            var x = bar.x, y = bar.y;
            if (x === undefined || y === undefined) return;

            /* Si hay ≥16 px de espacio arriba → dibujar encima;
               si no (barra muy alta o chart muy comprimido) → dibujar dentro */
            var textY, baseline;
            if (y - areaTop >= 16) {
                textY    = y - 4;
                baseline = 'bottom';
            } else {
                textY    = y + 14;
                baseline = 'top';
            }

            ctx.save();
            ctx.fillStyle    = '#000';
            ctx.font         = 'bold 12px sans-serif';
            ctx.textAlign    = 'center';
            ctx.textBaseline = baseline;
            ctx.fillText(value, x, textY);
            ctx.restore();
        });
    });
}

/* Plugin inline reutilizable — sin id para evitar conflictos al usarlo en múltiples charts */
function rcvMakeBarLabelPlugin() {
    return {
        afterDraw: function(chart) { rcvDrawBarLabels(chart); }
    };
}

function rcvRenderLineChart(canvasId, chartData, datasetLabel) {
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    try {
    new Chart(ctx, {
        type: 'line',
        data: {
            labels: chartData.labels,
            datasets: [{
                label: datasetLabel || '',
                data: chartData.data,
                borderColor: RCV_COLORS[0],
                backgroundColor: RCV_COLORS[0] + '22',
                fill: true,
                tension: 0.3,
                pointRadius: 4,
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: { legend: { display: false } },
            scales: { y: { beginAtZero: true, ticks: { precision: 0, color: '#000' } }, x: { ticks: { color: '#000' } } }
        }
    });
    } catch(e) { console.error('rcvRenderLineChart error:', e); rcvNoData(canvasId); }
}

function rcvRenderBarChart(canvasId, chartData, datasetLabel) {
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    var displayLabels = chartData.labels.map(function(l) {
        return (l && l.length > 25) ? l.substring(0, 22) + '...' : l;
    });
    var maxVal = Math.max.apply(null, chartData.data);
    try {
    new Chart(ctx, {
        type: 'bar',
        data: {
            labels: displayLabels,
            datasets: [{
                label: datasetLabel || '',
                data: chartData.data,
                backgroundColor: rcvGetColors(chartData.data.length),
                borderRadius: 4,
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: {
                legend: { display: false },
                tooltip: {
                    mode: 'index',
                    intersect: false,
                    callbacks: {
                        title: function(items) {
                            return chartData.labels[items[0].dataIndex] || '';
                        }
                    }
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: { precision: 0, color: '#000' },
                    suggestedMax: maxVal > 0 ? Math.ceil(maxVal * 1.2) : 10
                },
                x: { ticks: { maxRotation: 45, minRotation: 0, autoSkip: true, maxTicksLimit: 100, font: { size: 11 }, color: '#000' } }
            }
        },
        plugins: [rcvMakeBarLabelPlugin()]
    });
    } catch(e) { console.error('rcvRenderBarChart error:', e); rcvNoData(canvasId); }
}

/**
 * Dibuja porcentaje y valor en cada segmento de un doughnut.
 * Segmentos grandes (≥5%): etiqueta dentro del arco.
 * Segmentos pequeños (<5%): línea guía hacia afuera con etiqueta lateral.
 * Incluye resolución de colisiones verticales en etiquetas exteriores.
 */
function rcvDrawDoughnutLabels(chart) {
    var ctx     = chart.ctx;
    var dataset = chart.data.datasets[0];
    if (!dataset) return;
    var total = dataset.data.reduce(function(a, b) { return a + (b || 0); }, 0);
    if (!total) return;

    var meta = chart.getDatasetMeta(0);
    if (meta.hidden) return;

    var outsideLabels = [];

    meta.data.forEach(function(arc, index) {
        var value = dataset.data[index];
        if (!value) return;
        var pct      = value / total * 100;
        var midAngle = (arc.startAngle + arc.endAngle) / 2;
        var cosA     = Math.cos(midAngle);
        var sinA     = Math.sin(midAngle);
        var cx = arc.x, cy = arc.y;

        if (pct >= 5) {
            // ── etiqueta dentro del arco ──────────────────────────────────────
            var r = (arc.outerRadius + arc.innerRadius) / 2;
            var x = cx + cosA * r;
            var y = cy + sinA * r;
            ctx.save();
            ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.fillStyle = '#fff'; ctx.font = 'bold 11px sans-serif';
            ctx.fillText(Math.round(pct) + '%', x, y - 6);
            ctx.font = '10px sans-serif'; ctx.fillStyle = 'rgba(255,255,255,0.85)';
            ctx.fillText(value, x, y + 7);
            ctx.restore();

        } else if (pct >= 1) {
            // ── acumular para resolver colisiones después ─────────────────────
            var r1      = arc.outerRadius + 5;
            var r2      = arc.outerRadius + 18;
            var onRight = cosA >= 0;
            outsideLabels.push({
                x1: cx + cosA * r1, y1: cy + sinA * r1,
                x2: cx + cosA * r2, y2: cy + sinA * r2,
                onRight: onRight,
                text: Math.round(pct) + '% (' + value + ')'
            });
        }
    });

    // ── resolver colisiones verticales por lado ───────────────────────────────
    var lineH = 14;
    ['right', 'left'].forEach(function(side) {
        var group = outsideLabels
            .filter(function(l) { return l.onRight === (side === 'right'); })
            .sort(function(a, b) { return a.y2 - b.y2; });

        // Empujar hacia abajo los que se solapan
        for (var i = 1; i < group.length; i++) {
            if (group[i].y2 - group[i-1].y2 < lineH) {
                group[i].y2 = group[i-1].y2 + lineH;
            }
        }
        // Empujar hacia arriba si se pasaron del canvas
        var canvasH = chart.canvas.height / (window.devicePixelRatio || 1);
        for (var j = group.length - 1; j >= 1; j--) {
            if (group[j].y2 > canvasH - 5) group[j].y2 = canvasH - 5;
            if (group[j].y2 - group[j-1].y2 < lineH) {
                group[j-1].y2 = group[j].y2 - lineH;
            }
        }
    });

    // ── dibujar etiquetas exteriores ──────────────────────────────────────────
    outsideLabels.forEach(function(l) {
        var elbowLen = 14;
        var xElbow   = l.x2 + (l.onRight ? elbowLen : -elbowLen);
        var textX    = xElbow + (l.onRight ? 3 : -3);

        ctx.save();
        ctx.strokeStyle = '#94a3b8'; ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(l.x1, l.y1);
        ctx.lineTo(l.x2, l.y2);
        ctx.lineTo(xElbow, l.y2);
        ctx.stroke();

        ctx.fillStyle = '#1e293b'; ctx.font = '10px sans-serif';
        ctx.textAlign = l.onRight ? 'left' : 'right';
        ctx.textBaseline = 'middle';
        ctx.fillText(l.text, textX, l.y2);
        ctx.restore();
    });
}

function rcvMakeDoughnutLabelPlugin() {
    return { afterDraw: function(chart) { rcvDrawDoughnutLabels(chart); } };
}

function rcvRenderDoughnutChart(canvasId, chartData) {
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }

    var box = ctx.closest('.rcv-chart-box');
    if (box) box.style.height = '450px';

    try {
    new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: chartData.labels,
            datasets: [{
                data: chartData.data,
                backgroundColor: rcvGetColors(chartData.data.length),
                borderWidth: 2,
            }]
        },
        options: {
            animation: false,
            responsive: true,
            maintainAspectRatio: false,
            layout: { padding: { top: 30, bottom: 30, left: 55, right: 55 } },
            plugins: {
                legend: {
                    position: 'bottom',
                    labels: { font: { size: 13, weight: '600' }, color: '#1e293b', boxWidth: 13, padding: 12 }
                },
                tooltip: {
                    callbacks: {
                        label: function(item) {
                            var total = item.dataset.data.reduce(function(a,b){return a+(b||0);},0);
                            var pct = total ? Math.round(item.parsed / total * 100) : 0;
                            return ' ' + item.label + ': ' + item.parsed + ' (' + pct + '%)';
                        }
                    }
                }
            }
        },
        plugins: [rcvMakeDoughnutLabelPlugin()]
    });
    } catch(e) { console.error('rcvRenderDoughnutChart error:', e); rcvNoData(canvasId); }
}

function rcvRenderStackedBarChart(canvasId, chartData) {
    /* chartData = { labels:[], datasets:[{label, data:[]},...] } */
    var ctx = document.getElementById(canvasId);
    if (!ctx || !chartData || !chartData.labels || !chartData.labels.length) { rcvNoData(canvasId); return; }
    var ds = chartData.datasets.map(function(d, i) {
        return Object.assign({ backgroundColor: RCV_COLORS[i % RCV_COLORS.length] }, d);
    });
    var maxVal = 0;
    chartData.labels.forEach(function(_, i) {
        var col = ds.reduce(function(s, d) { return s + (d.data[i] || 0); }, 0);
        if (col > maxVal) maxVal = col;
    });
    try {
    new Chart(ctx, {
        type: 'bar',
        data: { labels: chartData.labels, datasets: ds },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: { mode: 'index', intersect: false },
            plugins: {
                legend: { position: 'bottom', labels: { font: { size: 11 }, boxWidth: 12, padding: 8 } },
                tooltip: { mode: 'index', intersect: false }
            },
            scales: {
                x: { stacked: true },
                y: {
                    stacked: true,
                    beginAtZero: true,
                    ticks: { precision: 0 },
                    suggestedMax: maxVal > 0 ? Math.ceil(maxVal * 1.2) : 10
                }
            }
        },
        plugins: [rcvMakeBarLabelPlugin()]
    });
    } catch(e) { console.error('rcvRenderStackedBarChart error:', e); rcvNoData(canvasId); }
}
